// PATTERN: restore binary from the trigger after the Postgres node.
// PROBE ADDITION: report exactly WHAT binary we are about to send to Azure.
const b = $('When Executed by WF-001').first().binary;
const d = (b && b.data) || {};
let bufLen = null, bufErr = null;
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  bufLen = Buffer.isBuffer(buf) ? buf.length : null;
} catch (e) { bufErr = String(e && e.message ? e.message : e).slice(0,200); }
const sendShape = {
  hasBinary: !!b,
  binaryKeys: b ? Object.keys(b) : [],
  fileName: d.fileName || null,
  mimeType: d.mimeType || null,
  fileSize_reported: d.fileSize || null,
  buffer_bytes_actual: bufLen,          // <-- the REAL payload size going to Azure
  buffer_error: bufErr,
};
console.log('[SW-005 SUBMIT-PROBE] about to send: ' + JSON.stringify(sendShape));
return [{ json: { ...$json, _sendShape: sendShape }, binary: b }];

// SUBMIT ADAPTER (provider-independent shell; Azure defaults).
// Extracts the poll URL from the submit response using provider config, and initialises poll state.
const cfg  = $('Load OCR Provider Settings').first().json.settings || {};
const poll = cfg.poll || {};
const HDR  = (poll.pollUrlHeader   || 'operation-location').toLowerCase();
const IVAL = Number(poll.pollIntervalMs ?? 2000);   // Azure: no faster than ~2s
const MAXA = Number(poll.maxAttempts    ?? 90);     // budget: 90 attempts
const MAXMS= Number(poll.maxElapsedMs   ?? 900000); // budget: 15 min hard ceiling

const res = $json;                       // fullResponse: { statusCode, headers, body }
const headers = res.headers || {};
// header lookup is case-insensitive
let pollUrl = null;
for (const k of Object.keys(headers)) { if (k.toLowerCase() === HDR) { pollUrl = headers[k]; break; } }
const status = res.statusCode;

if (status !== 202 || !pollUrl) {
  // Submit itself failed -> terminal failure, no polling.
  return [{ json: {
    _poll: { terminal: true, status: 'failed', attempt: 0, startedAt: Date.now(),
             intervalMs: IVAL, maxAttempts: MAXA, maxElapsedMs: MAXMS,
             error: `submit failed: HTTP ${status}` + (pollUrl ? '' : ' (no poll URL header)') },
    _result: null
  }}];
}
// Honor Retry-After from the submit response if present.
let firstWaitMs = IVAL;
const ra = headers['retry-after'] || headers['Retry-After'];
if (ra && !isNaN(Number(ra))) firstWaitMs = Math.max(IVAL, Number(ra) * 1000);

return [{ json: {
  _poll: { pollUrl, terminal: false, status: 'notStarted', attempt: 0, startedAt: Date.now(),
           waitMs: firstWaitMs, intervalMs: IVAL, maxAttempts: MAXA, maxElapsedMs: MAXMS, error: null },
  _result: null
}}];

// ===== RAW CAPTURE PROBE — records the untransformed Azure response at every poll. =====
const cfg  = $('Load OCR Provider Settings').first().json.settings || {};
const pc   = cfg.poll || {};
const STATUS_PATH = pc.statusPath      || 'status';
const SUCCESS     = pc.terminalSuccess || 'succeeded';
const FAILURE     = pc.terminalFailure || 'failed';
const RESULT_PATH = pc.resultPath      || 'analyzeResult';

const prev = $('submit() — capture pollUrl').first().json._poll;
let state = { ...prev, ...(($json && $json._poll) || {}) };
if (!state.pollUrl) state = { ...prev };

const res  = $json;
const body = res.body || {};
const headers = res.headers || {};
const httpStatus = res.statusCode;

state.attempt = (Number(state.attempt) || 0) + 1;
const elapsed = Date.now() - Number(state.startedAt);

// ---- RAW STRUCTURE CAPTURE (this is what we need to see) ----
const ar = body.analyzeResult;
const rawShape = {
  attempt: state.attempt,
  httpStatus,
  // Is fullResponse actually giving us {statusCode,headers,body}?
  itemTopLevelKeys: Object.keys(res || {}),
  bodyTopLevelKeys: Object.keys(body || {}),
  body_status: body.status ?? null,
  hasAnalyzeResult: ar != null,
  analyzeResult_keys: ar ? Object.keys(ar) : null,
  pages_length:      (ar && ar.pages)      ? ar.pages.length      : null,
  paragraphs_length: (ar && ar.paragraphs) ? ar.paragraphs.length : null,
  content_length:    (ar && typeof ar.content === 'string') ? ar.content.length : null,
  tables_length:     (ar && ar.tables)     ? ar.tables.length     : null,
  // page numbers actually present -> reveals truncation vs single-page
  pageNumbers: (ar && ar.pages) ? ar.pages.map(p => p.pageNumber).slice(0, 30) : null,
  // response size proxy
  approxBodyChars: JSON.stringify(body).length,
};
console.log('[RAW POLL] ' + JSON.stringify(rawShape));

const opStatus = String(STATUS_PATH.split('.').reduce((o,k)=> (o||{})[k], body) ?? '').toLowerCase();
const isSuccess = opStatus === String(SUCCESS).toLowerCase();
const isFailure = opStatus === String(FAILURE).toLowerCase();
const overAttempts = state.attempt >= Number(state.maxAttempts);
const overElapsed  = elapsed      >= Number(state.maxElapsedMs);

let result = null, terminal = false, status = opStatus || 'running', error = null;
if (isSuccess) {
  terminal = true; status = 'succeeded';
  result = RESULT_PATH.split('.').reduce((o,k)=> (o||{})[k], body) ?? body;
} else if (isFailure) {
  terminal = true; status = 'failed'; error = JSON.stringify(body.error || body).slice(0,500);
} else if (httpStatus >= 400) {
  terminal = true; status = 'failed'; error = 'poll HTTP ' + httpStatus;
} else if (overAttempts || overElapsed) {
  terminal = true; status = 'timeout'; error = 'budget exhausted';
}
let waitMs = Number(state.intervalMs) || 2000;
const ra = headers['retry-after'] || headers['Retry-After'];
if (ra && !isNaN(Number(ra))) waitMs = Math.max(waitMs, Number(ra)*1000);
if (httpStatus === 429) waitMs = Math.max(waitMs*2, 5000);
state.waitMs = waitMs; state.terminal = terminal; state.status = status;
state.error = error; state.httpStatus = httpStatus;
state.rawShape = rawShape;   // carry the evidence forward

return [{ json: { _poll: state, _result: result, _rawShape: rawShape } }];

// Dump the RAW response structure from EVERY poll run — untransformed.
const NODE='poll() — evaluate';
let maxRun=0; try { maxRun=$(NODE).runIndex||0; } catch(e){}
const rows=[];
for(let r=0;r<=maxRun;r++){
  let items=[]; try{ items=$(NODE).all(0,r)||[]; }catch(e){}
  for(const it of items){ if(it&&it.json&&it.json._rawShape) rows.push({runIndex:r, ...it.json._rawShape}); }
}
const terms=[];
for(let r=0;r<=maxRun;r++){
  let items=[]; try{ items=$(NODE).all(0,r)||[]; }catch(e){}
  for(const it of items){ const j=it.json; if(j&&j._poll&&j._poll.terminal===true) terms.push(j); }
}
const fin=terms.length?terms[terms.length-1]:null;
let sendShape=null;
try{ sendShape=$('Re-attach Binary (pattern)').first().json._sendShape; }catch(e){}
let submitShape=null;
try{ const s=$('submit() — POST Analyze').first().json; submitShape={statusCode:s.statusCode, headers:Object.keys(s.headers||{}), bodyKeys:Object.keys(s.body||{})}; }catch(e){}
const out={
  whatWeSentToAzure: sendShape,
  submitResponse: submitShape,
  pollRunIndex: maxRun,
  rawResponsesPerPoll: rows,
  terminalFound: terms.length,
  terminal_rawShape: fin ? fin._rawShape : null,
  terminal_result_pages: (fin && fin._result && fin._result.pages) ? fin._result.pages.length : null,
  terminal_result_paragraphs: (fin && fin._result && fin._result.paragraphs) ? fin._result.paragraphs.length : null,
  terminal_result_contentLen: (fin && fin._result && typeof fin._result.content==='string') ? fin._result.content.length : null,
};
console.log('[SW-005 RAW PROBE] '+JSON.stringify(out,null,2));
return [{ json: { _probe: out } }];

// Select the TERMINAL poll iteration.
// n8n semantics: each pass of the Wait-loop is a separate RUN of 'poll() — evaluate'.
// $('poll() — evaluate').all() returns items of ONE run only (runIndex defaults to 0) — that is
// why a stale 'running' iteration (with _result=null) was being picked. We must walk EVERY run.
function allPollRuns() {
  const out = [];
  let maxRun = 0;
  try { maxRun = $('poll() — evaluate').runIndex || 0; } catch (e) { maxRun = 0; }
  for (let r = 0; r <= maxRun; r++) {
    let items = [];
    try { items = $('poll() — evaluate').all(0, r) || []; } catch (e) { items = []; }
    for (const it of items) if (it && it.json) out.push(it.json);
  }
  return out;
}
function terminalPoll() {
  const runs = allPollRuns();
  const term = runs.filter(j => j && j._poll && j._poll.terminal === true);
  if (term.length) return term[term.length - 1];
  // Failure path: tolerate absence; report what we saw.
  return runs.length ? runs[runs.length - 1] : {};
}
// Terminal failure/timeout -> ocr=null so WF-001's node-if-ocr routes to the §154 HUMAN_REVIEW path.
const incoming = $('When Executed by WF-001').first().json;
const final = terminalPoll();
const p = final._poll || {};
return [{ json: { ...incoming, ocr: null,
  ocrError: { status: p.status || 'failed', attempts: p.attempt || 0,
              message: p.error || 'OCR failed' } } }];
